#include <stdio.h>
#include <string.h>
int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    char str[1005];
    while (T--) {
        scanf("%s", str);
        putchar(str[7]);
        if (T) putchar('\n');
    }
    return 0;
}

